import { encodeSudoku } from '@sudoku/sencode';
import { derived } from 'svelte/store';
import { hints } from './hints';
import { gameSession } from './game-session';

const initialGridStore = derived(gameSession, ($gameSession) => $gameSession.initialGrid);
const userGridStore = derived(gameSession, ($gameSession) => $gameSession.currentGrid);

function createGrid() {
	return {
		subscribe: initialGridStore.subscribe,

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

function createUserGrid() {
	return {
		subscribe: userGridStore.subscribe,

		set(pos, value) {
			return gameSession.guess(pos, value);
		},

		applyHint(pos) {
			const changed = gameSession.applyHint(pos);
			if (changed) {
				hints.useHint();
			}
			return changed;
		},

		undo() {
			return gameSession.undo();
		},

		redo() {
			return gameSession.redo();
		},
	};
}

export const userGrid = createUserGrid();
export const invalidCells = derived(gameSession, ($gameSession) => $gameSession.invalidCells);
export const canUndo = derived(gameSession, ($gameSession) => $gameSession.canUndo);
export const canRedo = derived(gameSession, ($gameSession) => $gameSession.canRedo);
